import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.Crpw6aS5.js";const h=JSON.parse(`{"title":"Partage d'archives","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/sharing.md","filePath":"fr/guide/sharing.md"}`),n={name:"fr/guide/sharing.md"};function s(l,e,d,o,u,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="partage-d-archives" tabindex="-1">Partage d&#39;archives <a class="header-anchor" href="#partage-d-archives" aria-label="Permalink to &quot;Partage d&#39;archives&quot;">​</a></h1><p>La fonctionnalité de partage permet de générer des <strong>liens temporaires</strong> pour partager un mail archivé avec quelqu&#39;un qui n&#39;a pas de compte sur l&#39;application.</p><h2 id="creer-un-lien-de-partage" tabindex="-1">Créer un lien de partage <a class="header-anchor" href="#creer-un-lien-de-partage" aria-label="Permalink to &quot;Créer un lien de partage&quot;">​</a></h2><p>Depuis la page <strong>Partage</strong> (menu Outils) :</p><ol><li>Cliquez sur un mail archivé</li><li>Choisissez la <strong>durée de validité</strong> (1 heure à 30 jours)</li><li>Optionnellement, définissez un <strong>nombre maximum d&#39;accès</strong></li><li>Le lien est généré et peut être copié dans le presse-papiers</li></ol><h2 id="parametres-d-un-partage" tabindex="-1">Paramètres d&#39;un partage <a class="header-anchor" href="#parametres-d-un-partage" aria-label="Permalink to &quot;Paramètres d&#39;un partage&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paramètre</th><th>Description</th><th style="text-align:center;">Valeur par défaut</th></tr></thead><tbody><tr><td><strong>Durée</strong></td><td>Temps pendant lequel le lien est valide</td><td style="text-align:center;">24 heures</td></tr><tr><td><strong>Accès max</strong></td><td>Nombre de fois que le lien peut être utilisé</td><td style="text-align:center;">Illimité</td></tr></tbody></table><h2 id="securite" tabindex="-1">Sécurité <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Sécurité&quot;">​</a></h2><ul><li>Les liens utilisent un <strong>token cryptographique de 64 caractères</strong> (256 bits d&#39;entropie)</li><li>Les liens expirent automatiquement — nettoyage toutes les heures</li><li>Les mails <strong>chiffrés</strong> ne peuvent pas être partagés</li><li>Le contenu est servi dans une <strong>iframe sandboxée</strong> (pas d&#39;exécution de scripts)</li><li>Chaque accès est comptabilisé</li></ul><h2 id="gestion-des-liens" tabindex="-1">Gestion des liens <a class="header-anchor" href="#gestion-des-liens" aria-label="Permalink to &quot;Gestion des liens&quot;">​</a></h2><p>La page de partage affiche tous vos liens actifs avec :</p><ul><li>Le sujet et l&#39;expéditeur du mail partagé</li><li>La date d&#39;expiration</li><li>Le nombre d&#39;accès</li></ul><p>Vous pouvez <strong>révoquer</strong> un lien à tout moment en cliquant sur l&#39;icône de suppression.</p><h2 id="vue-publique" tabindex="-1">Vue publique <a class="header-anchor" href="#vue-publique" aria-label="Permalink to &quot;Vue publique&quot;">​</a></h2><p>Les personnes qui reçoivent le lien accèdent à une page publique épurée affichant :</p><ul><li>Le sujet, l&#39;expéditeur et la date du mail</li><li>Le contenu HTML ou texte du mail</li><li>Un badge « Mail partagé via lien temporaire »</li></ul><p>Aucune authentification n&#39;est requise pour consulter un lien valide.</p><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Méthode</th><th>Endpoint</th><th style="text-align:center;">Auth</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/shares</code></td><td style="text-align:center;">Oui</td><td>Lister mes partages</td></tr><tr><td><code>POST</code></td><td><code>/api/shares</code></td><td style="text-align:center;">Oui</td><td>Créer un lien</td></tr><tr><td><code>DELETE</code></td><td><code>/api/shares/:id</code></td><td style="text-align:center;">Oui</td><td>Révoquer un lien</td></tr><tr><td><code>GET</code></td><td><code>/api/shares/public/:token</code></td><td style="text-align:center;">Non</td><td>Accéder au mail partagé</td></tr></tbody></table>',19)])])}const g=t(n,[["render",s]]);export{h as __pageData,g as default};
